// helps ensure that wakeups of wait()ing
// parents are not lost. helps obey the
// memory model when using p->parent.
// must be acquired before any p->lock.
struct spinlock wait_lock;
struct spinlock futex_lock;

// Allocate a page for each process's kernel stack.
// Map it high in memory, followed by an invalid
// guard page.
void
proc_mapstacks(pagetable_t kpgtbl)
{
  struct proc *p;
#ifdef RISCV
  for(p = proc; p < &proc[NPROC]; p++) {
    uint64 va = KSTACK((int) (p - proc));
    for (uint64 off = 0; off < KSTACKSIZE; off += PGSIZE) {
      char *pa = kalloc();
      if(pa == 0)
        panic("kalloc");
      kvmmap(kpgtbl, va + off, (uint64)pa, PGSIZE, PTE_R | PTE_W);
    }
  }
#elif defined(LOONGARCH)

  for(p = proc; p < &proc[NPROC]; p++) {
    uint64 va = KSTACK((int) (p - proc));
    for (uint64 off = 0; off < KSTACKSIZE; off += PGSIZE) {
      char *pa = kalloc();
      if(pa == 0)
        panic("kalloc");
      if(mappages(kpgtbl, va + off, PGSIZE, (uint64)pa,  PTE_NX | PTE_P | PTE_W | PTE_MAT | PTE_D | PTE_PLV) != 0)
        panic("kvmmap");
    }

  }
#endif
}

// initialize the proc table.
void
procinit(void)
{
  struct proc *p;

  initlock(&pid_lock, "nextpid");
  initlock(&wait_lock, "wait_lock");
  initlock(&futex_lock, "futex_lock");
  for(p = proc; p < &proc[NPROC]; p++) {
      initlock(&p->lock, "proc");
      p->state = UNUSED;
      p->kstack = KSTACK((int) (p - proc));
  }
}

// Must be called with interrupts disabled,
// to prevent race with process being moved
// to a different CPU.
int
cpuid()
{
  int id = r_tp();
  return id;
}

// Return this CPU's cpu struct.
// Interrupts must be disabled.
struct cpu*
mycpu(void)
{
  int id = cpuid();
  struct cpu *c = &cpus[id];
  return c;
}

// Return the current struct proc *, or zero if none.
struct proc*
myproc(void)
{
  push_off();
  struct cpu *c = mycpu();
  struct proc *p = c->proc;
  pop_off();
  return p;
}

int
allocpid()
{
  int pid;

  acquire(&pid_lock);
  pid = nextpid;
  nextpid = nextpid + 1;
  release(&pid_lock);
  return pid;
}

// Look in the process table for an UNUSED proc.
// If found, initialize state required to run in the kernel,
// and return with p->lock held.
// If there are no free procs, or a memory allocation fails, return 0.
static struct proc*
allocproc(void)
{
  struct proc *p;
  for(p = proc; p < &proc[NPROC]; p++) {
    acquire(&p->lock);
    if(p->state == UNUSED) {
      goto found;
    } else {
      release(&p->lock);
    }
  }
  return 0;

found:
  p->uid = 0;
  p->gid = 0;
  p->pid = allocpid();
  p->thread_group_pid = p->pid;
  p->state = USED;

  // printf("%p\n", p);

  // Allocate a trapframe page.
  if((p->trapframe = (struct trapframe *)kalloc()) == 0){
    freeproc(p);
    release(&p->lock);
    return 0;
  }

  // An empty user page table.
  p->pagetable = proc_pagetable(p);
  if(p->pagetable == 0){
    freeproc(p);
    release(&p->lock);
    return 0;
  }

  //Signal
  p->sig = (struct sighand*)kmalloc(sizeof(struct sighand));
  p->block.val = 0;


  // Set up new context to start executing at forkret,
  // which returns to user space.
  memset(&p->context, 0, sizeof(p->context));
  p->context.ra = (uint64)forkret;
  p->context.sp = p->kstack + KSTACKSIZE;
  memset(&p->vma, 0, NVMA * sizeof(struct vm_area));
  return p;
}

// free a proc structure and the data hanging from it,
// including user pages.
// p->lock must be held.
static void
freeproc(struct proc *p)
{

  if(p->trapframe)
    kfree((void*)p->trapframe);

  p->trapframe = 0;
  if(p->pagetable) {
    for(int i = 0; i < NVMA; i++) {
      if(p->vma[i].used) {
        uvmunmap(p->pagetable, p->vma[i].addr, PGROUNDUP(p->vma[i].len) / PGSIZE, !p->shared_vm);
        if(!p->shared_vm && p->vma[i].vfile != NULL)
          get_fops()->close(p->vma[i].vfile);
        p->vma[i].used = 0;
      }
    }
    if(p->shared_vm)
      proc_free_thread_pagetable(p->pagetable, p->sz);
    else
      proc_freepagetable(p->pagetable, p->sz);
  }

  p->pagetable = 0;
  p->sz = 0;
  memset(&p->vma, 0, NVMA * sizeof(struct vm_area));
  p->pid = 0;
  p->parent = 0;
  p->name[0] = 0;
  p->chan = 0;
  p->chan2 = 0;
  p->thread_group_pid = 0;
  p->futex_owner_pid = 0;
  p->futex_uaddr = 0;
  p->killed = 0;
  p->xstate = 0;
  p->clear_child_tid = 0;
  p->join_futex = 0;
  p->robust_list = 0;
  p->robust_list_len = 0;
  p->shared_vm = 0;
  p->is_thread = 0;


  //Signal
  p->sig_frame = 0;
  p->block.val = 0;

  if (p->sig) {
    kfree(p->sig);
  }
  p->sig = 0;

  memset((void*)((p->kstack)), 0, KSTACKSIZE);

  p->state = UNUSED;
}

// Create a user page table for a given process, with no user memory,
// but with trampoline and trapframe pages.
pagetable_t
proc_pagetable(struct proc *p)
{
  pagetable_t pagetable;

  // An empty page table.
  pagetable = uvmcreate();
  if(pagetable == 0)
    return 0;
#ifdef RISCV
  // map the trampoline code (for system call return)
  // at the highest user virtual address.
  // only the supervisor uses it, on the way
  // to/from user space, so not PTE_U.
  if(mappages(pagetable, TRAMPOLINE, PGSIZE,
              (uint64)trampoline, PTE_R | PTE_X) < 0){
    uvmfree(pagetable, 0);
    return 0;
  }

  if(mappages(pagetable, SIG_TRAMPOLINE, PGSIZE,
            (uint64)sig_trampoline, PTE_R | PTE_X | PTE_U) < 0) {
    uvmunmap(pagetable, TRAMPOLINE, 1, 0);
    uvmfree(pagetable, 0);
    return 0;
            }

  // map the trapframe page just below the trampoline page, for
  // trampoline.S.
  if(mappages(pagetable, TRAPFRAME, PGSIZE,
              (uint64)(p->trapframe), PTE_R | PTE_W) < 0){
    uvmunmap(pagetable, TRAMPOLINE, 1, 0);
    uvmunmap(pagetable, SIG_TRAMPOLINE, 1, 0);
    uvmfree(pagetable, 0);
    return 0;
  }
#elif defined(LOONGARCH)
  if(mappages(pagetable, TRAPFRAME, PGSIZE,
              (uint64)(p->trapframe), PTE_NX | PTE_P | PTE_W | PTE_MAT | PTE_D) < 0){
    uvmfree(pagetable, 0);
    return 0;
              }


  if(mappages(pagetable, SIG_TRAMPOLINE, PGSIZE,
          (uint64)sig_trampoline, PTE_P | PTE_MAT | PTE_D) < 0) {
    printf("Fail to map sig_trampoline\n");
    uvmunmap(pagetable, TRAPFRAME, 1, 0);
    uvmfree(pagetable, 0);
    return 0;
          }


#endif
  static int first = 0;
  if (!first) {
    printf("sig_trampoline: %p %p\n",sig_trampoline, walk(pagetable, SIG_TRAMPOLINE, 0));
    first = 1;
  }
  return pagetable;
}

// Free a process's page table, and free the
// physical memory it refers to.
void
proc_freepagetable(pagetable_t pagetable, uint64 sz)
{
#ifdef RISCV
  uvmunmap(pagetable, TRAMPOLINE, 1, 0);
#endif
  uvmunmap(pagetable, TRAPFRAME, 1, 0);
  uvmunmap(pagetable, SIG_TRAMPOLINE, 1, 0);


  uvmfree(pagetable, sz);
}

void
proc_free_thread_pagetable(pagetable_t pagetable, uint64 sz)
{
#ifdef RISCV
  uvmunmap(pagetable, TRAMPOLINE, 1, 0);
#endif
  uvmunmap(pagetable, TRAPFRAME, 1, 0);
  uvmunmap(pagetable, SIG_TRAMPOLINE, 1, 0);
  uvmfree_shared(pagetable, sz);
}

