static char *
append_uint(char *dst, uint64 n)
{
    char tmp[32];
    int i = 0;

    if (n == 0) {
        *dst++ = '0';
        return dst;
    }

    while (n > 0 && i < (int)sizeof(tmp)) {
        tmp[i++] = '0' + n % 10;
        n /= 10;
    }
    while (i > 0) {
        *dst++ = tmp[--i];
    }
    return dst;
}

static char *
append_str(char *dst, const char *src)
{
    while (*src) {
        *dst++ = *src++;
    }
    return dst;
}

static int
read_sysfile(struct file *f, uint64 addr, int n)
{
    char buf[256];
    char *p = buf;
    uint xticks;
    int len;
    int off;
    int nr;

    if (n <= 0) {
        return 0;
    }

    if (!strcmp(f->f_path, "/proc/interrupts")) {
        if (f->f_pos != 0) {
            return 0;
        }
        char *tmp = kmalloc(1024);
        if (tmp == NULL) {
            panic("read_sysfile: kalloc failed\n");
        }
        len = read_interrupts(tmp);
        if (len < 0) {
            len = 0;
        }
        if (len > n) {
            len = n;
        }
        if (copyout(myproc()->pagetable, addr, tmp, len) != 0) {
            kfree(tmp);
            return -1;
        }
        kfree(tmp);
        f->f_pos += len;
        return len;
    }

    acquire(&tickslock);
    xticks = ticks;
    release(&tickslock);

    if (!strcmp(f->f_path, "/proc/uptime")) {
        uint64 sec = xticks / 100;
        uint64 cent = xticks % 100;
        p = append_uint(p, sec);
        *p++ = '.';
        *p++ = '0' + cent / 10;
        *p++ = '0' + cent % 10;
        p = append_str(p, " 0.00\n");
    } else if (!strcmp(f->f_path, "/proc/stat")) {
        p = append_str(p, "cpu  ");
        p = append_uint(p, xticks);
        p = append_str(p, " 0 ");
        p = append_uint(p, xticks);
        p = append_str(p, " 0 0 0 0 0 0 0\n");
        p = append_str(p, "cpu0 ");
        p = append_uint(p, xticks);
        p = append_str(p, " 0 ");
        p = append_uint(p, xticks);
        p = append_str(p, " 0 0 0 0 0 0 0\n");
        p = append_str(p, "intr 0\nctxt 0\nbtime 0\nprocesses ");
        p = append_uint(p, countprocs());
        p = append_str(p, "\nprocs_running 1\nprocs_blocked 0\n");
    } else if (!strcmp(f->f_path, "/proc/meminfo")) {
        p = append_str(p, "MemTotal:       131072 kB\nMemFree:         65536 kB\n");
    } else if (!strcmp(f->f_path, "/proc/mounts")) {
        p = append_str(p, "/dev/root / ext4 rw 0 0\n");
    } else {
        return 0;
    }

    len = p - buf;
    off = f->f_pos;
    if (off >= len) {
        return 0;
    }
    nr = len - off;
    if (nr > n) {
        nr = n;
    }
    if (copyout(myproc()->pagetable, addr, buf + off, nr) != 0) {
        return -1;
    }
    f->f_pos += nr;
    return nr;
}


// Allocate a file structure.
struct file*
filealloc(void)
{
    struct file *f;

    acquire(&ftable.lock);
    for(f = ftable.file; f < ftable.file + NFILE; f++){
        if(f->f_count == 0){
            f->f_count = 1;
            release(&ftable.lock);
            return f;
        }
    }
    release(&ftable.lock);
    return 0;
}

// Increment ref count for file f.
struct file*
filedup(struct file *f)
{
    acquire(&ftable.lock);
    if(f->f_count < 1)
        panic("filedup");
    f->f_count++;
    release(&ftable.lock);
    return f;
}

// Close file f.  (Decrement ref count, close when reaches 0.)
void
fileclose(struct file *f)
{
    struct file ff;

    acquire(&ftable.lock);
    if(f->f_count < 1)
        panic("fileclose");
    if(--f->f_count > 0){
        release(&ftable.lock);
        return;
    }
    ff = *f;
    f->f_count = 0;
    f->f_type = FD_NONE;
    release(&ftable.lock);

    if(ff.f_type == FD_PIPE){
        pipeclose(ff.f_pipe, get_fops()->writable(&ff));
    } else if(ff.f_type == FD_REG || ff.f_type == FD_DEVICE){
        /*
         *file中需要得到filesystem的类型
         *但是这里暂时只支持EXT4
         */
        if (vfs_ext_is_dir(ff.f_path) == 0) {
            vfs_ext_dirclose(&ff);
        } else {
            vfs_ext_fclose(&ff);
        }
        if (ff.removed) {
            vfs_ext_rm(ff.f_path);
            ff.removed = 0;
        }
    } else if (ff.f_type == FD_SOCKET) {
        socketclose(f->f_socket, f->f_socketnum);
        f->f_socketnum = -1;
        f->f_socketflags = 0;

    }
}

