int pagefault_handler(uint64 va, uint64 cause) {
  /*
   *TODO: 支持lazy allocation和cow
   */
  int i;
  struct proc *p = myproc();
  for (i = NVMA - 1;i >= 0; i--) {
    if(p->vma[i].used && p->vma[i].addr <= va && va <= p->vma[i].addr + p->vma[i].len - 1) {
      break;
    }
  }
  if (i < 0) {
    return -1;
  } else {
    uint64 fault_page = PGROUNDDOWN(va);
    if(walkaddr(p->pagetable, fault_page) != 0)
      return 0;

    int pte_flags = PTE_U;
    if(p->vma[i].prot & PROT_READ) pte_flags |= PTE_R;
    if(p->vma[i].prot & PROT_WRITE) pte_flags |= PTE_W;
    if(p->vma[i].prot & PROT_EXEC) pte_flags |= PTE_X;
    if((p->shared_vm || p->is_thread) &&
       reuse_fault_page_from_threads(p, fault_page, pte_flags) == 0)
      return 0;
    struct file *f = p->vma[i].vfile;
    // 读导致的页面错误
    // if(cause == 13 && get_fops()->readable(f) == 0) return -1;
    // 写导致的页面错误
    // if(cause == 15 && get_fops()->writable(f) == 0) return -1;

    void *pa = kalloc();
    if (pa == NULL) {
      return -1;
    }
    memset(pa, 0, PGSIZE);
    if (f != NULL) {
      int offset = p->vma[i].offset + PGROUNDDOWN(va - p->vma[i].addr);
      int readbytes = get_fops()->readat(f, (uint64)pa, PGSIZE, offset);
      if (readbytes == 0) {
        kfree(pa);
        return -1;
      }
    }
    if(mappages(p->pagetable, fault_page, PGSIZE, (uint64)pa, pte_flags) != 0) {
      kfree(pa);
      return -1;
    }
    share_fault_page_with_threads(p, fault_page, (uint64)pa, pte_flags);
    return 0;
  }

}

//
// handle an interrupt, exception, or system call from user space.
// called from trampoline.S
//
void
usertrap(void)
{
  int which_dev = 0;

  if((r_sstatus() & SSTATUS_SPP) != 0)
    panic("usertrap: not from user mode");

  // send interrupts and exceptions to kerneltrap(),
  // since we're now in the kernel.
  w_stvec((uint64)kernelvec);

  struct proc *p = myproc();

  // save user program counter.
  p->trapframe->epc = r_sepc();
  uint64 cause = r_scause();
  if(cause == 8){
    // system call

    if(killed(p))
      exit(-1);

    // sepc points to the ecall instruction,
    // but we want to return to the next instruction.
    p->trapframe->epc += 4;

    // an interrupt will change sepc, scause, and sstatus,
    // so enable only now that we're done with those registers.
    intr_on();

    syscall();
  } else if((which_dev = devintr()) != 0){

    // ok
  } else if (cause == 2) {
    p->killed = 1;
  } else if (cause == 13 || cause == 15) {
    //缺页故障处理
    uint64 fault_va = r_stval();

    if(pagefault_handler(fault_va, cause) != 0) {
      p->killed = 1;
    }

  } else {
    printf("usertrap(): unexpected scause %p pid=%d\n", r_scause(), p->pid);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
    setkilled(p);
  }

  if(killed(p))
    exit(-1);

  // give up the CPU if this is a timer interrupt.
  if(which_dev == 2) {
    timeslice++; //让一个进程连续执行若干时间片，printf线程不安全
    if(timeslice >= 5){
      timeslice = 0;
      yield();
    }
  }
  handle_signal();
  // printf("%p\n", p->trapframe->ra);
  usertrapret();
}

//
// return to user space
//
void
usertrapret(void)
{
  struct proc *p = myproc();

  // we're about to switch the destination of traps from
  // kerneltrap() to usertrap(), so turn off interrupts until
  // we're back in user space, where usertrap() is correct.
  intr_off();

  w_stvec(TRAMPOLINE + (uservec - trampoline));

  // set up trapframe values that uservec will need when
  // the process next re-enters the kernel.
  p->trapframe->kernel_satp = r_satp();         // kernel page table
  p->trapframe->kernel_sp = p->kstack + KSTACKSIZE; // process's kernel stack
  p->trapframe->kernel_trap = (uint64)usertrap;
  p->trapframe->kernel_hartid = r_tp();         // hartid for cpuid()


  // set up the registers that trampoline.S's sret will use
  // to get to user space.

  // set S Previous Privilege mode to User.
  unsigned long x = r_sstatus();
  x &= ~SSTATUS_SPP; // clear SPP to 0 for user mode
  x |= SSTATUS_SPIE; // enable interrupts in user mode
  w_sstatus(x);

  // set S Exception Program Counter to the saved user pc.
  w_sepc(p->trapframe->epc);

  // tell trampoline.S the user page table to switch to.
  // printf("[usertrapret]p->pagetable: %p\n", p->pagetable);
  uint64 satp = MAKE_SATP(p->pagetable);

  // jump to trampoline.S at the top of memory, which
  // switches to the user page table, restores user registers,
  // and switches to user mode with sret.
  uint64 fn = TRAMPOLINE + (userret - trampoline);
  ((void (*)(uint64,uint64))fn)(TRAPFRAME + cpuid() * sizeof(struct trapframe), satp);
}

// interrupts and exceptions from kernel code go here via kernelvec,
// on whatever the current kernel stack is.
void 
kerneltrap()
{
  int which_dev = 0;
  uint64 sepc = r_sepc();
  uint64 sstatus = r_sstatus();
  uint64 scause = r_scause();

  if((sstatus & SSTATUS_SPP) == 0)
    panic("kerneltrap: not from supervisor mode");
  if(intr_get() != 0)
    panic("kerneltrap: interrupts enabled");

  if((which_dev = devintr()) == 0){
    printf("scause %p\n", scause);
    printf("sepc=%p stval=%p\n", r_sepc(), r_stval());
    panic("kerneltrap");
  }

  // give up the CPU if this is a timer interrupt.
  if(which_dev == 2 && myproc() != 0 && myproc()->state == RUNNING) {
    timeslice++; //让一个进程连续执行若干时间片，printf线程不安全
    if(timeslice >= 5){
      timeslice = 0;
      yield();
    }
  }


  // the yield() may have caused some traps to occur,
  // so restore trap registers for use by kernelvec.S's sepc instruction.
  w_sepc(sepc);
  w_sstatus(sstatus);
}

