int flags2perm(int flags)
{
#ifdef RISCV
    int perm = 0;
    if(flags & 0x1)
      perm = PTE_X;
    if(flags & 0x2)
      perm |= PTE_W;
    return perm;
#elif defined(LOONGARCH)
    int perm = PTE_P | PTE_PLV | PTE_MAT | PTE_D;
    if((flags & 0x1) == 0) {
      perm |= PTE_NX;
    }
    if(flags & 0x2) {
      perm |= PTE_W;
    }
    return perm;
#endif
}

static int
read_interp_path(struct inode *ip, struct proghdr *ph, char *interp)
{
  if(ph->filesz == 0 || ph->filesz >= MAXPATH)
    return -1;
  memset(interp, 0, MAXPATH);
  if(ip->i_op->read(ip, 0, (uint64)interp, ph->off, ph->filesz) != ph->filesz)
    return -1;
  interp[MAXPATH - 1] = 0;
  return 0;
}

static int
loadinterp(pagetable_t pagetable, char *path, uint64 base, uint64 *entry, uint64 *map_end)
{
  int i, off;
  struct elfhdr elf;
  struct inode *ip;
  struct proghdr ph;
  uint64 end = base;
  uint64 load_bias;

  if((ip = namei(path)) == 0)
    return -1;
  ip->i_op->lock(ip);

  if(ip->i_op->read(ip, 0, (uint64)&elf, 0, sizeof(elf)) != sizeof(elf))
    goto bad;
  if(elf.magic != ELF_MAGIC)
    goto bad;

  load_bias = (elf.type == ELF_TYPE_DYN) ? base : 0;
  if(entry)
    *entry = load_bias + elf.entry;

  for(i = 0, off = elf.phoff; i < elf.phnum; i++, off += sizeof(ph)){
    if(ip->i_op->read(ip, 0, (uint64)&ph, off, sizeof(ph)) != sizeof(ph))
      goto bad;
    if(ph.type != ELF_PROG_LOAD)
      continue;
    if(ph.memsz < ph.filesz)
      goto bad;
    if(load_bias + ph.vaddr < load_bias)
      goto bad;
    if(load_bias + ph.vaddr + ph.memsz < load_bias + ph.vaddr)
      goto bad;

    uint64 seg_start = PGROUNDDOWN(load_bias + ph.vaddr);
    uint64 seg_end = PGROUNDUP(load_bias + ph.vaddr + ph.memsz);
    uint64 old_end = PGROUNDUP(end);
    if(old_end < seg_start)
      old_end = seg_start;

    uint64 newsz = uvmalloc(pagetable, old_end, seg_end, flags2perm(ph.flags));
    if(newsz == 0 || newsz == (uint64)-1)
      goto bad;
    end = seg_end;

    uint margin_size = 0;
    if(((load_bias + ph.vaddr) % PGSIZE) != 0)
      margin_size = (load_bias + ph.vaddr) % PGSIZE;

    if(loadseg(pagetable, seg_start, ip, PGROUNDDOWN(ph.off), ph.filesz + margin_size) < 0)
      goto bad;
  }

  ip->i_op->unlock(ip);
  if(map_end)
    *map_end = end;
  return 0;

bad:
  ip->i_op->unlock(ip);
  return -1;
}

