uint64 sys_get_robust_list(void) {
  int pid;
  uint64 headaddr, lenaddr;
  struct proc *p;
  struct proc *cur = myproc();

  argint(0, &pid);
  argaddr(1, &headaddr);
  argaddr(2, &lenaddr);

  p = cur;
  if(pid != 0 && pid != cur->pid) {
    p = 0;
    for(struct proc *q = proc; q < &proc[NPROC]; q++) {
      acquire(&q->lock);
      if(q->pid == pid) {
        p = q;
        release(&q->lock);
        break;
      }
      release(&q->lock);
    }
    if(p == 0)
      return -1;
  }

  if(headaddr && copyout(cur->pagetable, headaddr, (char *)&p->robust_list,
                         sizeof(p->robust_list)) < 0)
    return -1;
  if(lenaddr && copyout(cur->pagetable, lenaddr, (char *)&p->robust_list_len,
                        sizeof(p->robust_list_len)) < 0)
    return -1;
  return 0;
}

struct robust_list_head {
  uint64 list_next;
  int64 futex_offset;
  uint64 list_op_pending;
};

static void
handle_robust_node(struct proc *p, uint64 node, int64 futex_offset)
{
  uint64 uaddr;
  int word;

  if(node == 0)
    return;
  uaddr = node + futex_offset;
  if(copyin(p->pagetable, (char *)&word, uaddr, sizeof(word)) < 0)
    return;
  if((word & FUTEX_TID_MASK) != p->pid)
    return;
  word = (word & FUTEX_WAITERS) | FUTEX_OWNER_DIED;
  if(copyout(p->pagetable, uaddr, (char *)&word, sizeof(word)) < 0)
    return;
  acquire(&futex_lock);
  futex_wake_locked(futex_owner_pid(p), uaddr, 1);
  release(&futex_lock);
}

void
exit_robust_list(struct proc *p)
{
  struct robust_list_head head;
  uint64 cur, next;

  if(p->robust_list == 0)
    return;
  if(copyin(p->pagetable, (char *)&head, p->robust_list, sizeof(head)) < 0)
    return;

  handle_robust_node(p, head.list_op_pending, head.futex_offset);

  cur = head.list_next;
  for(int i = 0; i < FUTEX_COUNT && cur && cur != p->robust_list; i++) {
    if(copyin(p->pagetable, (char *)&next, cur, sizeof(next)) < 0)
      break;
    handle_robust_node(p, cur, head.futex_offset);
    cur = next;
  }
}

