static int
mmap_range_overlaps(uint64 addr, uint64 len, uint64 vaddr, uint64 vlen)
{
    return addr < vaddr + vlen && vaddr < addr + len;
}

static uint64
find_mmap_addr(struct proc *p, uint64 hint, uint64 len, int flags)
{
#ifdef LOONGARCH
    uint64 addr;
    uint64 limit;
    addr = hint ? PGROUNDUP(hint) : 0x40000000UL;
    if(addr < 0x40000000UL)
        addr = 0x40000000UL;
    limit = 0x100000000UL;
#else
    uint64 addr = hint ? PGROUNDUP(hint) : 0x40000000UL;
    if(addr < 0x40000000UL)
        addr = 0x40000000UL;
    uint64 limit = USTACK_GURAD_PAGE;
#endif

    while(addr < limit && len <= limit - addr) {
        int moved = 0;
        for(int i = 0; i < NVMA; i++) {
            if(!p->vma[i].used)
                continue;
            if(mmap_range_overlaps(addr, len, p->vma[i].addr, p->vma[i].len)) {
                addr = PGROUNDUP(p->vma[i].addr + p->vma[i].len);
                moved = 1;
                break;
            }
        }
        if(!moved)
            return addr;
    }

    return 0;
}

static void
share_vma_with_threads(struct proc *p, struct vm_area *vma)
{
    struct proc *leader = p->is_thread ? p->parent : p;

    acquire(&wait_lock);
    for(struct proc *tp = proc; tp < &proc[NPROC]; tp++) {
        if(tp == p || tp->state == UNUSED)
            continue;
        if(tp != leader && (!tp->shared_vm || tp->parent != leader))
            continue;
        int slot = -1;
        for(int i = 0; i < NVMA; i++) {
            if(tp->vma[i].used && tp->vma[i].addr == vma->addr) {
                slot = i;
                break;
            }
            if(slot < 0 && !tp->vma[i].used)
                slot = i;
        }
        if(slot < 0)
            continue;

        tp->vma[slot] = *vma;
        if(vma->vfile)
            get_fops()->dup(vma->vfile);
        uvmshare_range(p->pagetable, tp->pagetable, vma->addr, vma->len);
    }
    release(&wait_lock);
}

static void
share_brk_with_threads(struct proc *p, uint64 oldsz, uint64 newsz)
{
    struct proc *leader = p->is_thread ? p->parent : p;

    if(newsz <= oldsz)
        return;

    acquire(&wait_lock);
    for(struct proc *tp = proc; tp < &proc[NPROC]; tp++) {
        if(tp == p || tp->state == UNUSED)
            continue;
        if(tp != leader && (!tp->shared_vm || tp->parent != leader))
            continue;
        if(uvmshare_range(p->pagetable, tp->pagetable, oldsz, newsz - oldsz) == 0)
            tp->sz = newsz;
    }
    release(&wait_lock);
}

static void
unmap_range_from_threads(struct proc *p, uint64 addr, uint64 len, int do_free)
{
    struct proc *leader = p->is_thread ? p->parent : p;

    acquire(&wait_lock);
    for(struct proc *tp = proc; tp < &proc[NPROC]; tp++) {
        if(tp == p || tp->state == UNUSED)
            continue;
        if(tp != leader && (!tp->shared_vm || tp->parent != leader))
            continue;
        uvmunmap(tp->pagetable, addr, len / PGSIZE, do_free);
    }
    release(&wait_lock);
}

static void
remove_vmas_in_range(struct proc *p, uint64 addr, uint64 len)
{
    uint64 end = addr + len;

    for(int i = 0; i < NVMA; i++) {
        if(!p->vma[i].used)
            continue;
        uint64 vstart = p->vma[i].addr;
        uint64 vend = p->vma[i].addr + p->vma[i].len;
        if(!mmap_range_overlaps(addr, len, vstart, p->vma[i].len))
            continue;

        if(addr <= vstart && end >= vend) {
            if(p->vma[i].vfile)
                get_fops()->close(p->vma[i].vfile);
            memset(&p->vma[i], 0, sizeof(p->vma[i]));
        } else if(addr <= vstart) {
            uint64 cut = end - vstart;
            p->vma[i].addr += cut;
            p->vma[i].len -= cut;
            p->vma[i].offset += cut;
        } else if(end >= vend) {
            p->vma[i].len = addr - vstart;
        } else {
            p->vma[i].len = addr - vstart;
        }
    }
}

