    }
    if (copyout(pg, (uint64)&(uts->release), (char*)RELEASE, sizeof(RELEASE)) < 0) {
        return -1;
    }
    if (copyout(pg, (uint64)&(uts->version), (char*)VERSION, sizeof(VERSION)) < 0) {
        return -1;
    }
    if (copyout(pg, (uint64)&(uts->machine), (char*)MACHINE, sizeof(MACHINE)) < 0) {
