extern struct spinlock wait_lock;

int timeslice = 0;

static void
share_fault_page_with_threads(struct proc *p, uint64 va, uint64 pa, uint64 flags)
{
  struct proc *leader = p->is_thread ? p->parent : p;

  acquire(&wait_lock);
  for(struct proc *tp = proc; tp < &proc[NPROC]; tp++) {
    if(tp == p || tp->state == UNUSED)
      continue;
    if(tp != leader && (!tp->shared_vm || tp->parent != leader))
      continue;

    pte_t *dst = walk(tp->pagetable, va, 0);
    if(dst && (*dst & PTE_V)) {
      *dst = PA2PTE(pa) | flags | PTE_V;
      continue;
    }
    mappages(tp->pagetable, va, PGSIZE, pa, flags);
  }
  release(&wait_lock);
}

static int
reuse_fault_page_from_threads(struct proc *p, uint64 va, uint64 flags)
{
  struct proc *leader = p->is_thread ? p->parent : p;

  acquire(&wait_lock);
  for(struct proc *tp = proc; tp < &proc[NPROC]; tp++) {
    if(tp == p || tp->state == UNUSED)
      continue;
    if(tp != leader && (!tp->shared_vm || tp->parent != leader))
      continue;

    pte_t *src = walk(tp->pagetable, va, 0);
    if(src == 0 || (*src & PTE_V) == 0)
      continue;

    uint64 pa = PTE2PA(*src);
    pte_t *dst = walk(p->pagetable, va, 0);
    if(dst && (*dst & PTE_V)) {
      release(&wait_lock);
      return 0;
    }
    int ok = mappages(p->pagetable, va, PGSIZE, pa, flags) == 0;
    release(&wait_lock);
    return ok ? 0 : -1;
  }
  release(&wait_lock);
  return -1;
}

void
trapinit(void)
{

  initlock(&tickslock, "time");

  uint32 ecfg = ( 0U << CSR_ECFG_VS_SHIFT ) | HWI_VEC | TI_VEC;
  uint64 tcfg = 0x1000000UL | CSR_TCFG_EN | CSR_TCFG_PER;

  w_csr_ecfg(ecfg);
  w_csr_tcfg(tcfg);

  w_csr_eentry((uint64)kernelvec);
  w_csr_tlbrentry((uint64)handle_tlbr);
  w_csr_merrentry((uint64)handle_merr);
  intr_on();
}

int pagefault_handler(uint64 va, uint64 cause) {
  /*
   *TODO: 支持lazy allocation和cow
   */
  int i;
  struct proc *p = myproc();
  for (i = NVMA - 1;i >= 0; i--) {
    if(p->vma[i].used && p->vma[i].addr <= va && va <= p->vma[i].addr + p->vma[i].len - 1) {

      break;
    }
  }

  if (i < 0) {
    uint64 fault_page = PGROUNDDOWN(va);
    if(fault_page != 0 && va < p->sz) {
      if(walkaddr(p->pagetable, fault_page) != 0)
        return 0;
      uint64 pte_flags = PTE_U | PTE_D | PTE_MAT | PTE_P | PTE_W | PTE_NX;
      if((p->shared_vm || p->is_thread) &&
         reuse_fault_page_from_threads(p, fault_page, pte_flags) == 0)
        return 0;
      void *pa = kalloc();
      if(pa == NULL)
        return -1;
      memset(pa, 0, PGSIZE);
      if(mappages(p->pagetable, fault_page, PGSIZE, (uint64)pa, pte_flags) != 0) {
        kfree(pa);
        return -1;
      }
      share_fault_page_with_threads(p, fault_page, (uint64)pa, pte_flags);
      return 0;
    }
    return -1;
  } else {
    uint64 fault_page = PGROUNDDOWN(va);
    if(walkaddr(p->pagetable, fault_page) != 0)
      return 0;

    int pte_flags = PTE_U | PTE_D | PTE_MAT | PTE_P;
    if(!(p->vma[i].prot & PROT_READ)) pte_flags |= PTE_NR;
    if(p->vma[i].prot & PROT_WRITE) pte_flags |= PTE_W;
    if(!(p->vma[i].prot & PROT_EXEC)) pte_flags |= PTE_NX;
    if((p->shared_vm || p->is_thread) &&
       reuse_fault_page_from_threads(p, fault_page, pte_flags) == 0)
      return 0;
    struct file *f = p->vma[i].vfile;


    void *pa = kalloc();
    if (pa == NULL) {
      return -1;
    }
    memset(pa, 0, PGSIZE);
    if (f != NULL) {
      int offset = p->vma[i].offset + PGROUNDDOWN(va - p->vma[i].addr);
      int readbytes = get_fops()->readat(f, (uint64)pa, PGSIZE, offset);
      if (readbytes == 0) {
        kfree(pa);
        return -1;
      }
    }

    if(mappages(p->pagetable, fault_page, PGSIZE, (uint64)pa, pte_flags) != 0) {
      kfree(pa);
      return -1;
    }
    share_fault_page_with_threads(p, fault_page, (uint64)pa, pte_flags);
    return 0;
  }

}

