//
void
usertrap(void)
{
  int which_dev = 0;
  int ecode = ((r_csr_estat() & CSR_ESTAT_ECODE) >> 16);

  if((r_csr_prmd() & PRMD_PPLV) == 0)
    panic("usertrap: not from user mode");

  // send interrupts and exceptions to kerneltrap(),
  // since we're now in the kernel.
  w_csr_eentry((uint64)kernelvec);

  struct proc *p = myproc();

  // save user program counter.
  p->trapframe->era = r_csr_era();
  if( ecode == 0xb){
    // system call

    if(p->killed)
      exit(-1);

    // sepc points to the ecall instruction,
    // but we want to return to the next instruction.
    p->trapframe->era += 4;

    // an interrupt will change crmd & prmd registers,
    // so don't enable until done with those registers.
    intr_on();
    syscall();
  } else if((ecode == 0x1 || ecode == 0x2)){
    //缺页故障处理
    if (pagefault_handler(r_csr_badv(), ecode) < 0) {
      p->killed = 1;
    }
  } else if (ecode == 0xf) {
    // Floating-point disabled in user mode: enable FPE and retry
    // the same instruction instead of skipping it.
    uint32 euen = r_csr_euen();
    if ((euen & CSR_EUEN_FPE) == 0) {
      w_csr_euen(euen | CSR_EUEN_FPE);
    } else {
      // FPE already enabled: treat as fatal to avoid trap loops.
      p->killed = 1;
    }
  }else if((which_dev = devintr()) != 0){
    // ok
  } else {
    p->killed = 1;
  }

  if(p->killed)
    exit(-1);

  // give up the CPU if this is a timer interrupt.
  if(which_dev == 2) {
    timeslice++; //让一个进程连续执行若干时间片，printf线程不安全
    if(timeslice >= 10){
      timeslice = 0;
      yield();
    }
  }

  handle_signal();

  usertrapret();
}

