        // printf("[blockdev_bread] blk_id: %d, blk_cnt: %d\n", blk_id + i, blk_cnt);
        struct buf *b = bread(1, blk_id + i);
        memmove((void*)buf_ptr, b->data, BSIZE);
        buf_ptr += BSIZE;
        brelse(b);
