void get_absolute_path(const char *path, const char *cwd, char *absolute_path) {

    if (path == NULL) {
        strncpy(absolute_path, cwd, strlen(cwd));
    } else if (path[0] == '/') {
        strcpy(absolute_path, path);
    } else {
        strcpy(absolute_path, cwd);
        strcat(absolute_path, "/");
        strcat(absolute_path, path);
    }
    // handle ./ and ../
    char *p = absolute_path;
    while (*p != '\0') {
        if (*p == '.' && *(p + 1) == '/') {
            strcpy(p, p + 2);
        } else if (*p == '.' && *(p + 1) == '.' && *(p + 2) == '/') {
            char *q = p - 2;
            while (q >= absolute_path && *q != '/') {
                q--;
            }
            if (q >= absolute_path) {
                strcpy(q + 1, p + 3);
                p = q;
            } else {
                strcpy(absolute_path, p + 3);
                p = absolute_path;
            }
        } else {
            p++;
        }
    }

    /* handle trailing . and .. */
    p = absolute_path + strlen(absolute_path) - 2;
    if ((*p == '/' || *p == '.') && *(p + 1) == '.' && *(p + 2) == '\0') {
        *p = *(p + 1) = *(p + 2) = '\0';
    }
    p--;
    if (*p == '/' && *(p + 1) == '.' && *(p + 2) == '.' && *(p + 3) == '\0') {
        if (p == absolute_path) {
            *(p + 1) = *(p + 2) = *(p + 3) = '\0';
            return;
        }
        char *q = p - 1;
        while (q >= absolute_path && *q != '/') {
            q--;
        }
        if (q >= absolute_path) {
            *q = '\0';
            p = q;
        } else {
            strcpy(absolute_path, p + 4);
            p = absolute_path;
        }
    }


    while (absolute_path[0] == '/' && absolute_path[1] == '/') {
        strcpy(absolute_path, absolute_path + 1);
    }
    size_t len = strlen(absolute_path);
    if (absolute_path[len - 1] == '/') {
        absolute_path[len - 1] = '\0';
        --len;
    }
    if (strlen(absolute_path) == 0) {
        strcpy(absolute_path, "/");
    } else if (absolute_path[0] != '/') {
        size_t len2 = strlen(absolute_path);
        char *x = absolute_path + len2;
        *(x + 1) = 0;
        while (x > absolute_path) {
            *x = *(x - 1);
            x--;
        }
        *x = '/';
    }
}

static int path_exists(const char *path)
{
    struct kstat st;
    return vfs_ext_stat(path, &st) == 0;
}

void resolve_library_path(const char *path, char *resolved_path)
{
    if (resolved_path != path) {
        strcpy(resolved_path, path);
    }
    int path_len = strlen(path);
    if (path_len > 3 && !strcmp(path + path_len - 3, ".so") && !path_exists(path)) {
        char lib_path[MAXPATH] = {0};
        const char *basename = path + path_len;

        while (basename > path && *(basename - 1) != '/') {
            basename--;
        }

        int dir_len = basename - path;
        if (dir_len + 4 + strlen(basename) < MAXPATH) {
            memmove(lib_path, path, dir_len);
            strcpy(lib_path + dir_len, "lib/");
            strcpy(lib_path + dir_len + 4, basename);
            if (path_exists(lib_path)) {
                strcpy(resolved_path, lib_path);
                return;
            }
        }
    }

    int is_lib = strncmp(path, "/lib/", 5) == 0;
    int is_lib64 = strncmp(path, "/lib64/", 7) == 0;
    if (!is_lib && !is_lib64) {
        return;
    }

    if (path_exists(path)) {
        return;
    }

    if (strncmp(path, "/lib/ld-musl-", 13) == 0 ||
        strncmp(path, "/lib64/ld-musl-", 15) == 0) {
        const char musl_loader[] = "/mnt/musl/lib/libc.so";
        if (path_exists(musl_loader)) {
            strcpy(resolved_path, musl_loader);
            return;
        }
    }

    const char *cwd = myproc()->cwd.path;
    const char *prefixes[] = {"/mnt/glibc/", "/mnt/musl/", NULL};

    if (strncmp(cwd, "/mnt/musl", 9) == 0) {
        prefixes[0] = "/mnt/musl/";
        prefixes[1] = "/mnt/glibc/";
    }

    for (int i = 0; prefixes[i] != NULL; i++) {
        char candidate[MAXPATH] = {0};
        strcpy(candidate, prefixes[i]);
        strcat(candidate, path + 1);
        if (path_exists(candidate)) {
            strcpy(resolved_path, candidate);
            return;
        }

        if (is_lib64) {
            memset(candidate, 0, sizeof(candidate));
            strcpy(candidate, prefixes[i]);
            strcat(candidate, "lib/");
            strcat(candidate, path + 7);
            if (path_exists(candidate)) {
                strcpy(resolved_path, candidate);
                return;
            }
        }

    }
}

