struct inode*
namei(char *path)
{
    char name[EXT4_PATH_LONG_MAX];
    get_absolute_path(path, myproc()->cwd.path, name);
    resolve_library_path(name, name);
    // printf("%s %s\n", name, myproc()->cwd.path);
