    int r = 0;
    struct vfs_ext4_blockdev *vbdev = fs->fs_data;

    if (vbdev == NULL) {
        r = -ENOMEM;
        return r;
    }

    ext4_umount(fs->path);
    if (r != EOK) {
        return r;
    }

    vfs_ext4_blockdev_destroy(vbdev);
    return EOK;
}

int vfs_ext_ioctl(struct file *f, int cmd, void *args) {
    int r = 0;
    struct ext4_file *file = (struct ext4_file *)f -> f_extfile;
    if (file == NULL) {
        panic("vfs_ext_ioctl: cannot get ext4 file\n");
    }

    switch (cmd) {
        case FIOCLEX:
            f->f_flags |= O_CLOEXEC;
        break;
        case FIONCLEX:
            f->f_flags &= ~O_CLOEXEC;
        break;
        case FIONREAD:
            r = ext4_fsize(file);
        break;
        case FIONBIO:
            break;
        case FIOASYNC:
            break;
        default:
            r = -EINVAL;
        break;
    }
    return r;
}

