int vfs_ext_read(struct file *f, int user_addr, const uint64 addr, int n) {

    if (f->f_type == FD_SYSFILE) {
        if (f->f_pos == -1) {
            return 0;
        }
        char *buf = kmalloc(n + 1);
        if (buf == NULL) {
            panic("vfs_ext_read: kalloc failed\n");
        }
        int byteread = read_interrupts(buf);
        if (copyout(myproc()->pagetable, addr, buf, byteread) != 0) {
            kfree(buf);
            return 0;
        }
        kfree(buf);
        f->f_pos = -1;
        return byteread;
    }

    uint64 byteread = 0;
    struct ext4_file *file = (struct ext4_file *)f -> f_extfile;
    if (file == NULL) {
        panic("vfs_ext_read: cannot get ext4 file\n");
    }
    int r = 0;
    if (user_addr) {
        char *buf = kmalloc(n + 1);
        uint64 mread = 0;
        if (buf == NULL) {
            panic("vfs_ext_read: kalloc failed\n");
        }
        r = ext4_fread(file, buf, n, &byteread);
        if (r != EOK) {
            kfree(buf);
            return 0;
        }
        if (copyout(myproc()->pagetable, addr, buf, byteread) != 0) {
            kfree(buf);
            return 0;
        }
        kfree(buf);
    } else {
        char *kbuf = (char *) addr;
        r = ext4_fread(file, kbuf, n, &byteread);
        if (r != EOK) {
            return 0;
        }
        memmove((char *) addr, kbuf, byteread);
    }
    f -> f_pos = file->fpos;

    return byteread;
}

