// Grow or shrink user memory by n bytes.
// Return 0 on success, -1 on failure.
int
growproc(int64 n)
{
  uint64 sz;
  struct proc *p = myproc();

  sz = p->sz;
  if(n > 0){
    if (sz >= MAXVA - PGSIZE)
      return -1;
    if ((uint64)n > (MAXVA - PGSIZE - sz))
      return -1;
#ifdef RISCV
    if((sz = uvmalloc(p->pagetable, sz, sz + n, PTE_W)) == 0) {
      return -1;
    }
#elif defined(LOONGARCH)
    if((sz = uvmalloc(p->pagetable, sz, sz + n, PTE_P|PTE_W|PTE_PLV|PTE_MAT|PTE_D)) == 0) {
      return -1;
    }
#endif
  } else if(n < 0){
    uint64 dec = (uint64)(-n);
    if (dec > sz)
      return -1;
    sz = uvmdealloc(p->pagetable, sz, sz + n);
  }
  p->sz = sz;
  return 0;
}

// Create a new process, copying the parent.
// Sets up child kernel stack to return as if from fork() system call.
int
fork(void)
{
  int i, pid;
  struct proc *np;
  struct proc *p = myproc();

  // Allocate process.
  if((np = allocproc()) == 0){
    return -1;
  }

  // Copy user memory from parent to child.
  if(uvmcopy(p->pagetable, np->pagetable, p->sz) < 0){
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;
  acquire(&p->lock);
  // copy saved user registers.
  *(np->trapframe) = *(p->trapframe);
  np->parent = p;  // 设置父进程
  release(&p->lock);
  // Cause fork to return 0 in the child.
  np->trapframe->a0 = 0;

  // increment reference counts on open file descriptors.
  for(i = 0; i < NOFILE; i++)
    if(p->ofile[i])
      np->ofile[i] = get_fops()->dup(p->ofile[i]);

  for(i = 0; i < NVMA; ++i) {
    if(p->vma[i].used) {
      memmove(&np->vma[i], &p->vma[i], sizeof(p->vma[i]));
      if(p->vma[i].vfile)
        get_fops()->dup(p->vma[i].vfile);
      if(uvmcopy_range(p->pagetable, np->pagetable, p->vma[i].addr, p->vma[i].len) < 0) {
        freeproc(np);
        release(&np->lock);
        return -1;
      }
    }
  }

  np->cwd.fs = p->cwd.fs;
  strcpy(np->cwd.path, p->cwd.path);

  strcpy(np->name, p->name);

  pid = np->pid;

  release(&np->lock);

  acquire(&wait_lock);
  np->parent = p;
  release(&wait_lock);

  acquire(&np->lock);
  np->state = RUNNABLE;
  release(&np->lock);


  return pid;
}

// Pass p's abandoned children to init.
// Caller must hold wait_lock.
void
reparent(struct proc *p)
{
  struct proc *pp;

  for(pp = proc; pp < &proc[NPROC]; pp++){
    if(pp->parent == p){
      pp->parent = initproc;
      wakeup(initproc);
    }
  }
}

